  // Figure out if one of the sets of cases form a contiguous range.
  SmallVectorImpl<ConstantInt *> *ContiguousCases = nullptr;
  BasicBlock *ContiguousDest = nullptr;
  BasicBlock *OtherDest = nullptr;
  if (!CasesA.empty() && casesAreContiguous(CasesA)) {
    ContiguousCases = &CasesA;
    ContiguousDest = DestA;
    OtherDest = DestB;
  } else if (casesAreContiguous(CasesB)) {
    ContiguousCases = &CasesB;
    ContiguousDest = DestB;
    OtherDest = DestA;
  } else {
    // Try to find if the complement of explicit cases within the valid range
    // forms a contiguous range. This handles cases like switch with explicit
    // cases {0, 4, 5} and default covering {1, 2, 3} when valid range is [0, 6).
    std::optional<ConstantRange> ValidRange;
    if (auto *Arg = dyn_cast<Argument>(SI->getCondition())) {
      ValidRange = Arg->getRange();
    }

    if (!ValidRange)
      return false;

    // Collect all explicit cases
    SmallVector<ConstantInt *, 16> AllExplicitCases;
    AllExplicitCases.append(CasesA.begin(), CasesA.end());
    AllExplicitCases.append(CasesB.begin(), CasesB.end());
    array_pod_sort(AllExplicitCases.begin(), AllExplicitCases.end(),
                   constantIntSortPredicate);

    // Check if explicit cases form prefix and/or suffix of valid range,
    // leaving a contiguous gap (complement) in the middle.
    // The complement is contiguous if explicit cases are:
    // - A prefix of valid range (complement is suffix)
    // - A suffix of valid range (complement is prefix)
    // - Both prefix and suffix (complement is middle)
    APInt ValidMin = ValidRange->getLower();
    APInt ValidMax = ValidRange->getUpper(); // exclusive
    unsigned BitWidth = ValidMin.getBitWidth();

    // Check if explicit cases form prefix/suffix pattern
    bool IsPrefix = true;
    bool IsSuffix = true;
    APInt ExpectedPrefix = ValidMin;
    APInt ExpectedSuffix = ValidMax - 1;

    for (ConstantInt *C : AllExplicitCases) {
      const APInt &Val = C->getValue();
      if (Val == ExpectedPrefix) {
        ExpectedPrefix = ExpectedPrefix + 1;
      } else {
        IsPrefix = false;
      }
      if (Val == ExpectedSuffix) {
        ExpectedSuffix = ExpectedSuffix - 1;
      } else {
        IsSuffix = false;
      }
    }

    // For the complement to be contiguous, explicit cases must form
    // prefix only, suffix only, or both (but not with a gap in between).
    // This means after processing all explicit cases, either:
    // - IsPrefix is true (explicit = prefix, complement = suffix)
    // - IsSuffix is true (explicit = suffix, complement = prefix)
    // - Both are true and they meet (explicit = prefix + suffix with no gap)
    // Actually, we need to check if there's exactly one contiguous gap.

    // Simplified check: the complement is contiguous if explicit cases
    // don't have any internal gaps. That is, all explicit cases are either
    // at the start (prefix) or at the end (suffix) of the valid range.
    // If we have explicit cases in the middle, the complement would be
    // split into two parts.

    // Let's check: sort explicit cases, then see if they form prefix/suffix
    bool ComplementContiguous = false;
    APInt ComplementMin, ComplementMax; // exclusive

    if (AllExplicitCases.empty()) {
      // All values in valid range go to default - already handled
      return false;
    }

    APInt FirstExplicit = AllExplicitCases.front()->getValue();
    APInt LastExplicit = AllExplicitCases.back()->getValue();

    // Check if explicit cases form a prefix: first explicit == ValidMin
    // and all values from ValidMin to some point are explicit
    if (FirstExplicit == ValidMin) {
      // Check if explicit cases are contiguous from ValidMin
      bool ContiguousFromStart = true;
      APInt Expected = ValidMin;
      for (ConstantInt *C : AllExplicitCases) {
        if (C->getValue() != Expected) {
          ContiguousFromStart = false;
          break;
        }
        Expected = Expected + 1;
      }
      if (ContiguousFromStart) {
        // Explicit cases form a prefix, complement is suffix
        ComplementMin = LastExplicit + 1;
        ComplementMax = ValidMax;
        ComplementContiguous = true;
      }
    }

    // Check if explicit cases form a suffix: last explicit == ValidMax - 1
    // and all values from some point to ValidMax-1 are explicit
    if (!ComplementContiguous && LastExplicit == ValidMax - 1) {
      bool ContiguousFromEnd = true;
      APInt Expected = ValidMax - 1;
      for (auto It = AllExplicitCases.rbegin(); It != AllExplicitCases.rend();
           ++It) {
        if ((*It)->getValue() != Expected) {
          ContiguousFromEnd = false;
          break;
        }
        Expected = Expected - 1;
      }
      if (ContiguousFromEnd) {
        // Explicit cases form a suffix, complement is prefix
        ComplementMin = ValidMin;
        ComplementMax = FirstExplicit;
        ComplementContiguous = true;
      }
    }

    // Check if explicit cases form both prefix and suffix (complement in middle)
    if (!ComplementContiguous && FirstExplicit == ValidMin &&
