      // Check if explicit cases are contiguous from start AND from end
      // with exactly one gap in the middle
      bool HasOneGap = true;
      APInt Expected = ValidMin;
      bool InPrefix = true;
      bool FoundGap = false;
      APInt GapStart, GapEnd;

      for (ConstantInt *C : AllExplicitCases) {
        APInt Val = C->getValue();
        if (InPrefix) {
          if (Val == Expected) {
            Expected = Expected + 1;
          } else {
            // Found start of gap
            InPrefix = false;
            FoundGap = true;
            GapStart = Expected;
            Expected = Val + 1;
          }
        } else {
          if (Val != Expected) {
            HasOneGap = false;
            break;
          }
          Expected = Expected + 1;
        }
      }

      if (HasOneGap && FoundGap && Expected == ValidMax) {
        // Exactly one gap from GapStart to the value before the first
        // non-prefix explicit case
        // Actually, we need to find where the gap ends
        // GapEnd is the first explicit case after the gap
        GapEnd = Expected; // This is the first value after the gap
        ComplementMin = GapStart;
        ComplementMax = GapEnd;
        ComplementContiguous = true;
      }
    }

    if (!ComplementContiguous)
      return false;

    // Build the complement cases
    ContiguousCases = new SmallVector<ConstantInt *, 16>();
    for (APInt V = ComplementMin; V.ult(ComplementMax); V = V + 1) {
      ContiguousCases->push_back(
          ConstantInt::get(SI->getCondition()->getType(), V));
    }

    // The complement goes to the default destination
    ContiguousDest = DestA;
    OtherDest = DestB;

    // Use complement-based offset: offset = -ComplementMin
    // This transforms: icmp ult (arg + offset), count
    // where count = ComplementMax - ComplementMin
  }
